import {
  getTile,
  idx,
  inBounds,
  neighbors8,
  type TileGrid,
} from "../map/index.js";
import { isWalkableTile, Terrain } from "../map/terrain.js";
import type { Rng } from "../rng/index.js";
import type { Position } from "../state/index.js";
import {
  CONNECTIVITY_ITERATION_CAP,
  roomContaining,
  type RoomRect,
} from "./generate.js";

export type PlacementKind = "enemy" | "item" | "trap" | "npc";

export type PlacementDistanceHint = "near_entrance" | "far_from_entrance";

export type PlacementHint = {
  readonly roomIndex?: number;
  readonly distance?: PlacementDistanceHint;
  readonly spread?: boolean;
};

export type PlacementRequest = {
  readonly id: string;
  readonly kind: PlacementKind;
  readonly hint?: PlacementHint;
};

export type PlacementDeviationReason =
  | "room_index_unsatisfiable"
  | "distance_hint_unsatisfiable"
  | "spread_hint_unsatisfiable";

export type PlacementDeviation = {
  readonly requestId: string;
  readonly hint: PlacementHint;
  readonly reasons: readonly PlacementDeviationReason[];
};

export type PlacementAllocation = {
  readonly requestId: string;
  readonly kind: PlacementKind;
  readonly position: Position;
};

export type AllocationErrorCode = "capacity_exhausted";

export type AllocationError = {
  readonly kind: "allocation-error";
  readonly code: AllocationErrorCode;
  readonly message: string;
  readonly legalCellCount: number;
  readonly requestCount: number;
};

export type AllocateCellsResult =
  | {
      readonly ok: true;
      readonly placements: readonly PlacementAllocation[];
      readonly deviations: readonly PlacementDeviation[];
    }
  | { readonly ok: false; readonly error: AllocationError };

export type PlacementGrid = {
  readonly grid: TileGrid;
  readonly entrance: Position;
  readonly stairsDown: Position;
  readonly rooms: readonly RoomRect[];
};

const manhattanDistance = (a: Position, b: Position): number =>
  Math.abs(a.x - b.x) + Math.abs(a.y - b.y);

const positionsEqual = (a: Position, b: Position): boolean =>
  a.x === b.x && a.y === b.y;

const positionKey = (position: Position): string => `${position.x},${position.y}`;

const isExitTerrain = (grid: TileGrid, position: Position): boolean => {
  if (!inBounds(grid, position)) {
    return true;
  }

  const terrain = getTile(grid, position).terrain;
  return terrain === Terrain.Entrance || terrain === Terrain.StairsDown;
};

const sortPositionsStable = (positions: readonly Position[]): Position[] =>
  [...positions].sort((a, b) => (a.y !== b.y ? a.y - b.y : a.x - b.x));

const reachableCellSet = (
  grid: TileGrid,
  entrance: Position,
): ReadonlySet<number> | null => {
  if (!inBounds(grid, entrance)) {
    return null;
  }

  const startIndex = idx(grid, entrance);
  const startTile = grid.tiles[startIndex];
  if (startTile === undefined || !isWalkableTile(startTile)) {
    return null;
  }

  const visited = new Set<number>([startIndex]);
  const queue: number[] = [startIndex];
  let iterations = 0;

  while (queue.length > 0) {
    iterations += 1;
    if (iterations > CONNECTIVITY_ITERATION_CAP) {
      return null;
    }

    const currentIndex = queue.shift();
    if (currentIndex === undefined) {
      break;
    }

    const current = {
      x: currentIndex % grid.width,
      y: Math.floor(currentIndex / grid.width),
    };

    for (const neighbor of neighbors8(grid, current)) {
      const neighborIndex = idx(grid, neighbor);
      if (visited.has(neighborIndex)) {
        continue;
      }

      const tile = grid.tiles[neighborIndex];
      if (tile === undefined || !isWalkableTile(tile)) {
        continue;
      }

      visited.add(neighborIndex);
      queue.push(neighborIndex);
    }
  }

  return visited;
};

export const collectLegalPlacementCells = (
  floor: PlacementGrid,
): readonly Position[] => {
  const reachable = reachableCellSet(floor.grid, floor.entrance);
  if (reachable === null) {
    return [];
  }

  const legal: Position[] = [];

  for (const index of reachable) {
    const position = {
      x: index % floor.grid.width,
      y: Math.floor(index / floor.grid.width),
    };

    if (
      positionsEqual(position, floor.entrance) ||
      positionsEqual(position, floor.stairsDown) ||
      isExitTerrain(floor.grid, position)
    ) {
      continue;
    }

    legal.push(position);
  }

  return sortPositionsStable(legal);
};

const filterByRoomIndex = (
  candidates: readonly Position[],
  rooms: readonly RoomRect[],
  roomIndex: number,
): readonly Position[] =>
  candidates.filter((position) => roomContaining(rooms, position) === roomIndex);

const filterByDistanceHint = (
  candidates: readonly Position[],
  entrance: Position,
  distance: PlacementDistanceHint,
): readonly Position[] => {
  if (candidates.length === 0) {
    return candidates;
  }

  const distances = candidates.map((position) => ({
    position,
    distance: manhattanDistance(position, entrance),
  }));

  const targetDistance =
    distance === "near_entrance"
      ? Math.min(...distances.map((entry) => entry.distance))
      : Math.max(...distances.map((entry) => entry.distance));

  return distances
    .filter((entry) => entry.distance === targetDistance)
    .map((entry) => entry.position);
};

const filterBySpread = (
  candidates: readonly Position[],
  occupied: ReadonlySet<string>,
): readonly Position[] => {
  if (candidates.length === 0 || occupied.size === 0) {
    return candidates;
  }

  const occupiedPositions = [...occupied].map((key) => {
    const [xText, yText] = key.split(",");
    return {
      x: Number(xText),
      y: Number(yText),
    };
  });

  const scored = candidates.map((position) => {
    const minDistance = occupiedPositions.reduce((best, occupiedPosition) => {
      const distance = manhattanDistance(position, occupiedPosition);
      return Math.min(best, distance);
    }, Number.POSITIVE_INFINITY);

    return { position, minDistance };
  });

  const bestSpread = Math.max(...scored.map((entry) => entry.minDistance));
  return scored
    .filter((entry) => entry.minDistance === bestSpread)
    .map((entry) => entry.position);
};

const applyHintFilters = (
  floor: PlacementGrid,
  candidates: readonly Position[],
  hint: PlacementHint | undefined,
  occupied: ReadonlySet<string>,
): {
  readonly hinted: readonly Position[];
  readonly satisfied: boolean;
  readonly reasons: readonly PlacementDeviationReason[];
} => {
  if (hint === undefined) {
    return { hinted: candidates, satisfied: true, reasons: [] };
  }

  let current = candidates;
  const reasons: PlacementDeviationReason[] = [];

  if (hint.roomIndex !== undefined) {
    const inRoom = filterByRoomIndex(current, floor.rooms, hint.roomIndex);
    if (inRoom.length === 0) {
      reasons.push("room_index_unsatisfiable");

      reasons.push("room_index_unsatisfiable");
      return { hinted: candidates, satisfied: false, reasons };
    }
    current = inRoom;
  }

  if (hint.distance !== undefined) {
    const byDistance = filterByDistanceHint(current, floor.entrance, hint.distance);
    if (byDistance.length === 0) {
      reasons.push("distance_hint_unsatisfiable");
      return { hinted: candidates, satisfied: false, reasons };
    }
    current = byDistance;
  }

  if (hint.spread === true) {
    const spread = filterBySpread(current, occupied);
    if (spread.length === 0) {
      reasons.push("spread_hint_unsatisfiable");
      return { hinted: candidates, satisfied: false, reasons };
    }
    current = spread;
  }

  return { hinted: current, satisfied: true, reasons };
};

const pickPosition = (candidates: readonly Position[], rng: Rng): Position => {
  const ordered = sortPositionsStable(candidates);
  return rng.pick(ordered);
};

export const allocateCells = (
  grid: PlacementGrid,
  requests: readonly PlacementRequest[],
  rng: Rng,
): AllocateCellsResult => {
  const legalCells = collectLegalPlacementCells(grid);

  if (requests.length > legalCells.length) {
    return {
      ok: false,
      error: {
        kind: "allocation-error",
        code: "capacity_exhausted",
        message: `cannot place ${requests.length} entities on ${legalCells.length} legal cells`,
        legalCellCount: legalCells.length,
        requestCount: requests.length,
      },
    };
  }

  const occupied = new Set<string>();
  const placements: PlacementAllocation[] = [];
  const deviations: PlacementDeviation[] = [];

  for (const request of requests) {
    const available = legalCells.filter(
      (position) => !occupied.has(positionKey(position)),
    );

    const { hinted, satisfied, reasons } = applyHintFilters(
      grid,
      available,
      request.hint,
      occupied,
    );

    if (!satisfied && request.hint !== undefined) {
      deviations.push({
        requestId: request.id,
        hint: request.hint,
        reasons,
      });
    }

    const position = pickPosition(satisfied ? hinted : available, rng);
    occupied.add(positionKey(position));
    placements.push({
      requestId: request.id,
      kind: request.kind,
      position,
    });
  }

  return {
    ok: true,
    placements,
    deviations,
  };
};

  return success(softCap.state, [...stepped.events, ...softCap.events]);
};

export const currentFloorRuntime = (state: GameState): FloorRuntime | null =>
  runtimeOpaque(state)?.knowledge?.run ?? null;

const enterFloor = (
  state: GameState,
  provider: FloorContentProvider,
  depth: number,
  gameConfig: GameConfig
): RunLoopResult => {
  if (depth < 1 || depth > gameConfig.runStructure.depthFloors) {
    return failure(state, {
      kind: "run-loop-error",
      code: "depth_out_of_range",
      depth,
      message: `depth ${depth} is outside run depth 1-${gameConfig.runStructure.depthFloors}`
    });
  }

  const band = depthBandForDepth(depth, gameConfig);
  const contentSeed = floorSeed(state.run.seed, depth);
  const contentResult = loadFloorContent(
    provider,
    depth,
    band,
    contentSeed,
    gameConfig
  );

  if (!contentResult.ok) {
    return failure(state, contentResult.error);
  }

  const generated = generateFloor(contentResult.content.params, gameConfig);
  if (!generated.ok) {
    return failure(state, {
      kind: "run-loop-error",
      code: "floor_generation_failed",
      depth,
      message: generated.error.message
    });
  }

  const requests = contentRequests(contentResult.content);
  const allocation = allocateCells(
    placementGrid(generated.floor),
    requests.map(({ request }) => request),
    runRng(state.run.seed).fork(`place:${depth}`)
  );

  if (!allocation.ok) {
    return failure(state, {
      kind: "run-loop-error",
      code: "placement_failed",
      depth,
      message: allocation.error.message
    });
  }

  const assembled = assembleEntities(
    state.ids.entityCounters,
    requests,
    allocation.placements
  );
  const hoard = hoardRuntime(requests, allocation.placements);
  const runtime: FloorRuntime = {
    depth,
    enteredTurn: state.run.turn,
    seed: contentSeed,
    entrance: generated.floor.entrance,
    stairsDown: generated.floor.stairsDown,
    roster: contentResult.content.roster,
    initialSpawnBudgetSpent: rosterCost(contentResult.content.roster),
    reinforcementSpawnBudgetSpent: 0,
    hoard
  };
  const floorId = `floor#${depth}`;
  const nextState = appendRunLog(
    {
      ...state,
      run: {
        ...state.run,
        depth,
        band
      },
      floor: {
        floorId,
        depth,
        band,
        geometry: createRuntimeGeometrySlot(
          `floor-geometry#${depth}`,
          generated.floor.grid,
          runtime
        )
      },
      player: {
        ...state.player,
        position: generated.floor.entrance
      },
      entities: assembled.entities,
      quests: withFloorQuest(state, contentResult.content.quest),
      ids: {
        ...state.ids,
        entityCounters: assembled.counters
      }
    },
    [
      runEvent(state.run.turn, "run_floor_entered", {
        floorId,
        depth,
        band,
        seed: contentSeed,
        rosterCost: runtime.initialSpawnBudgetSpent,
        spawnBudget: gameConfig.enemyDesign.spawnBudgetPoints[band],
        placementDeviationCount: allocation.deviations.length,
        hoardFeatureId: hoard?.id ?? null
      }),
      ...placementDeviationEvents(state.run.turn, allocation.deviations)
    ]
  );

  return success(nextState, nextState.log.slice(state.log.length));
};

const applySoftCap = (
  state: GameState,
  gameConfig: GameConfig
): { readonly state: GameState; readonly events: readonly RunEvent[] } => {
  const runtime = currentFloorRuntime(state);
  if (runtime === null) {
    return { state, events: [] };
  }

  const floorTurn = state.run.turn - runtime.enteredTurn;
  const softCap = gameConfig.runStructure.perFloorSoftCapTurns;
  const interval = gameConfig.runStructure.reinforcementIntervalTurns;

  if (floorTurn <= softCap || (floorTurn - softCap) % interval !== 0) {
    return { state, events: [] };
  }

  const wave = (floorTurn - softCap) / interval;
  const spawnBudget = gameConfig.enemyDesign.spawnBudgetPoints[state.run.band];
  const spent =
    runtime.initialSpawnBudgetSpent + runtime.reinforcementSpawnBudgetSpent;
  const budgetRemaining = Math.max(0, spawnBudget - spent);
  const candidates = runtime.roster.filter(
    (definition) => costOf(definition) <= budgetRemaining
  );

  if (candidates.length === 0) {
    const event = runEvent(state.run.turn, "run_boredom", {
      depth: state.run.depth,
      floorTurn,
      wave,
      budgetRemaining,
      reason: "budget_exhausted"
    });
    return { state: appendRunLog(state, [event]), events: [event] };
  }

  const cells = legalReinforcementCells(state);
  if (cells.length === 0) {
    const event = runEvent(state.run.turn, "run_boredom", {
      depth: state.run.depth,
      floorTurn,
      wave,
      budgetRemaining,
      reason: "no_legal_cell"
    });
    return { state: appendRunLog(state, [event]), events: [event] };
  }

  const rng = runRng(state.run.seed).fork(
    `reinforcement:${state.run.depth}:${wave}`
  );
  const definition = rng.pick(candidates);
  const position = pickStable(cells, rng);
  const allocation = allocateEntityId(state.ids.entityCounters, "enemy");
  const entity = assembleEnemy(definition, {
    id: allocation.id,
    position
  });
  const cost = costOf(definition);
  const nextRuntime: FloorRuntime = {
    ...runtime,
    reinforcementSpawnBudgetSpent: runtime.reinforcementSpawnBudgetSpent + cost
  };
  const nextBudgetRemaining = Math.max(0, budgetRemaining - cost);
  const events = [
    runEvent(state.run.turn, "run_boredom", {
      depth: state.run.depth,
      floorTurn,
      wave,
      budgetRemaining,
      reason: "reinforcement_spawned"
    }),
    runEvent(state.run.turn, "run_reinforcement_spawned", {
      entityId: allocation.id,
      definitionId: definition.id,
      depth: state.run.depth,
      position,
      cost,
      budgetRemaining: nextBudgetRemaining,
      wave
    })
  ];
  const nextState = appendRunLog(
    withRuntime(
      {
        ...state,
        entities: {
          ...state.entities,
          [entity.id]: entity
        },
        ids: {
          ...state.ids,
          entityCounters: allocation.entityCounters
        }
      },
      nextRuntime
    ),
    events
  );

  return { state: nextState, events };
};

const loadFloorContent = (
  provider: FloorContentProvider,
  depth: number,
  band: DepthBand,
  seed: string,
  gameConfig: GameConfig
):
  | { readonly ok: true; readonly content: FloorContent }
  | { readonly ok: false; readonly error: RunLoopError } => {
  let raw: unknown;

  try {
    raw = provider.getFloor(depth, seed);
  } catch (error) {
    return {
      ok: false,
      error: {
        kind: "run-loop-error",
        code: "provider_threw",
        depth,
        message:
          error instanceof Error
            ? error.message
            : "floor content provider threw a non-error value"
      }
    };
  }

  const record = asRecord(raw);
  if (record === null) {
    return malformed(depth, "provider result must be an object");
  }

  const params = parseRunFloorParams(record.params, depth, gameConfig);
  if (!params.ok) {
    return malformed(depth, params.message);
  }

  const roster = EnemyDefinitionSchema.array().safeParse(record.roster);
