138	export const parseManifest = (raw: string): ParseManifestResult => {
139	  const extracted = extractFirstJsonObject(raw);
140	  if (!extracted.ok) {
141	    return {
142	      ok: false,
143	      errors: [{ path: "$", message: extracted.message }],
144	    };
145	  }
146	
147	  let parsed: unknown;
148	  try {
149	    parsed = JSON.parse(extracted.json);
150	  } catch (error) {
151	    return {
152	      ok: false,
153	      errors: [
154	        {
155	          path: "$",
156	          message:
157	            error instanceof Error
158	              ? `invalid JSON: ${error.message}`
159	              : "invalid JSON",
160	        },
161	      ],
162	    };
163	  }
164	
165	  const result = FloorManifestSchema.safeParse(parsed);
166	  if (!result.success) {
167	    return {
168	      ok: false,
169	      errors: result.error.issues.map((issue) => ({
170	        path: formatIssuePath(issue.path),
171	        message: issue.message,
172	      })),
173	    };
174	  }
175	
176	  return { ok: true, manifest: result.data };
177	};
