 77	type CommandResult = {
 78	  readonly ok: boolean;
 79	  readonly stdout: string;
 80	  readonly stderr: string;
 81	  readonly summary: string;
 82	};
 83	
 84	const runCommand = (
 85	  command: string,
 86	  args: readonly string[],
 87	  timeoutMs: number,
 88	): Promise<CommandResult> =>
 89	  new Promise((resolve) => {
 90	    const child = spawn(command, args, {
 91	      stdio: ["ignore", "pipe", "pipe"],
 92	    });
 93	    const stdoutChunks: Buffer[] = [];
 94	    const stderrChunks: Buffer[] = [];
 95	    let settled = false;
 96	
 97	    const timeout = setTimeout(() => {
 98	      settled = true;
 99	      child.kill("SIGTERM");
100	      resolve({
101	        ok: false,
102	        stdout: Buffer.concat(stdoutChunks).toString("utf8"),
103	        stderr: Buffer.concat(stderrChunks).toString("utf8"),
104	        summary: `timed out after ${timeoutMs}ms`,
105	      });
106	    }, timeoutMs);
107	
108	    child.stdout.on("data", (chunk: Buffer) => {
109	      stdoutChunks.push(chunk);
110	    });
111	
112	    child.stderr.on("data", (chunk: Buffer) => {
113	      stderrChunks.push(chunk);
114	    });
115	
116	    child.on("error", (error) => {
117	      if (settled) {
118	        return;
119	      }
120	      settled = true;
121	      clearTimeout(timeout);
122	      resolve({
123	        ok: false,
124	        stdout: Buffer.concat(stdoutChunks).toString("utf8"),
125	        stderr: Buffer.concat(stderrChunks).toString("utf8"),
126	        summary: error.message,
127	      });
128	    });
129	
130	    child.on("close", (code, signal) => {
131	      if (settled) {
132	        return;
133	      }
134	      settled = true;
135	      clearTimeout(timeout);
136	
137	      const stderr = Buffer.concat(stderrChunks).toString("utf8");
138	      resolve({
139	        ok: code === 0,
140	        stdout: Buffer.concat(stdoutChunks).toString("utf8"),
141	        stderr,
142	        summary:
143	          code === 0
144	            ? "exit 0"
145	            : `exit ${code ?? "null"} signal ${signal ?? "null"} ${stderr}`,
146	      });
147	    });
148	  });
